namespace sv_49f97304388f487989137aeac2e7fda3.Services;

/// <summary>
/// Holds the currently selected warehouse for a single circuit (user session).
/// Registered as Scoped so each Blazor Server circuit gets its own instance.
/// </summary>
public sealed class WarehouseStateService
{
    private string _currentWarehouseId = "WH-1";

    public event Action? OnChange;

    public string CurrentWarehouseId => _currentWarehouseId;

    public static IReadOnlyList<(string Id, string Name)> AvailableWarehouses { get; } = new List<(string, string)>
    {
        ("WH-1", "Warehouse A"),
        ("WH-2", "Warehouse B"),
        ("WH-3", "Warehouse C"),
    };

    public void SetWarehouse(string warehouseId)
    {
        if (_currentWarehouseId == warehouseId) return;
        _currentWarehouseId = warehouseId;
        OnChange?.Invoke();
    }
}

namespace sv_49f97304388f487989137aeac2e7fda3.Services;

/// <summary>
/// Tracks low-stock alert counts per circuit. Provides a simulated async query
/// and an event so any subscribed component is notified when new data arrives.
/// Registered as Scoped (one per Blazor Server circuit).
/// </summary>
public sealed class InventoryAlertService
{
    private readonly Random _random = new();

    public int CurrentAlertCount { get; private set; }

    public event Action? OnAlertCountChanged;

    /// <summary>
    /// Simulates a database query that returns the number of items below minimum
    /// stock levels for the given warehouse.
    /// </summary>
    public Task<int> GetLowStockCountAsync(string warehouseId)
    {
        var count = _random.Next(0, 16);
        return Task.FromResult(count);
    }

    /// <summary>
    /// Called by the polling component after fetching new data.
    /// Stores the latest count and notifies all subscribers.
    /// </summary>
    public void UpdateAlertCount(int newCount)
    {
        CurrentAlertCount = newCount;
        OnAlertCountChanged?.Invoke();
    }
}

