@using sv_49f97304388f487989137aeac2e7fda3.Services
@rendermode InteractiveServer
@inject WarehouseStateService WarehouseState
@implements IDisposable

<div class="warehouse-selector">
    <label class="form-label text-white mb-1" for="warehouseSelect">Current Warehouse</label>
    <select id="warehouseSelect"
            class="form-select form-select-sm"
            value="@WarehouseState.CurrentWarehouseId"
            @onchange="OnWarehouseChanged">
        @foreach (var wh in WarehouseStateService.AvailableWarehouses)
        {
            <option value="@wh.Id">@wh.Name</option>
        }
    </select>
</div>

@code {
    private void OnWarehouseChanged(ChangeEventArgs e)
    {
        var newId = e.Value?.ToString();
        if (!string.IsNullOrEmpty(newId))
        {
            WarehouseState.SetWarehouse(newId);
        }
    }

    protected override void OnInitialized()
    {
        WarehouseState.OnChange += StateHasChanged;
    }

    public void Dispose()
    {
        WarehouseState.OnChange -= StateHasChanged;
    }
}

@using sv_49f97304388f487989137aeac2e7fda3.Services
@rendermode InteractiveServer
@inject InventoryAlertService AlertService
@implements IDisposable

<span class="alert-badge" title="Low-stock items">
    @if (AlertService.CurrentAlertCount > 0)
    {
        <span class="badge bg-danger rounded-pill">@AlertService.CurrentAlertCount</span>
    }
    else
    {
        <span class="badge bg-success rounded-pill">0</span>
    }
</span>

@code {
    protected override void OnInitialized()
    {
        AlertService.OnAlertCountChanged += OnAlertCountChanged;
    }

    private void OnAlertCountChanged()
    {
        InvokeAsync(StateHasChanged);
    }

    public void Dispose()
    {
        AlertService.OnAlertCountChanged -= OnAlertCountChanged;
    }
}

@page "/dashboard"
@using sv_49f97304388f487989137aeac2e7fda3.Services
@rendermode InteractiveServer
@inject WarehouseStateService WarehouseState
@inject InventoryAlertService AlertService
@implements IDisposable

<PageTitle>Dashboard</PageTitle>

<h1>Warehouse Dashboard</h1>

<div class="row mt-4">
    <div class="col-md-4">
        <div class="card">
            <div class="card-body text-center">
                <h5 class="card-title">Selected Warehouse</h5>
                <p class="card-text fs-4">@GetWarehouseName()</p>
            </div>
        </div>
    </div>

    <div class="col-md-4">
        <div class="card @(AlertService.CurrentAlertCount > 0 ? "border-danger" : "border-success")">
            <div class="card-body text-center">
                <h5 class="card-title">Low-Stock Alerts</h5>
                <p class="card-text fs-1 fw-bold @(AlertService.CurrentAlertCount > 0 ? "text-danger" : "text-success")">
                    @AlertService.CurrentAlertCount
                </p>
                <small class="text-muted">
                    @if (_isPolling)
                    {
                        <span>🟢 Polling active &mdash; refreshes every 10s</span>
                    }
                    else
                    {
                        <span>⏸ Polling paused</span>
                    }
                </small>
            </div>
        </div>
    </div>

    <div class="col-md-4">
        <div class="card">
            <div class="card-body text-center">
                <h5 class="card-title">Last Checked</h5>
                <p class="card-text fs-5">@(_lastChecked?.ToString("T") ?? "—")</p>
            </div>
        </div>
    </div>
</div>

@code {
    private CancellationTokenSource? _cts;
    private bool _isPolling;
    private DateTime? _lastChecked;

    protected override void OnInitialized()
    {
        WarehouseState.OnChange += OnWarehouseChanged;
        AlertService.OnAlertCountChanged += OnAlertCountChanged;
    }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            await StartPollingAsync();
        }
    }

    private async Task StartPollingAsync()
    {
        StopPolling();

        _cts = new CancellationTokenSource();
        _isPolling = true;
        var token = _cts.Token;

        // Fetch immediately, then every 10 seconds
        await PollOnceAsync();

        _ = Task.Run(async () =>
        {
            using var timer = new PeriodicTimer(TimeSpan.FromSeconds(10));
            try
            {
                while (await timer.WaitForNextTickAsync(token))
                {
                    await PollOnceAsync();
                }
            }
            catch (OperationCanceledException) { }
        }, token);
    }

    private async Task PollOnceAsync()
    {
        var count = await AlertService.GetLowStockCountAsync(WarehouseState.CurrentWarehouseId);
        _lastChecked = DateTime.Now;
        // This fires OnAlertCountChanged, updating all subscribers
        AlertService.UpdateAlertCount(count);
        await InvokeAsync(StateHasChanged);
    }

    private async void OnWarehouseChanged()
    {
        // Restart polling for the newly selected warehouse
        await InvokeAsync(async () => await StartPollingAsync());
    }

    private void OnAlertCountChanged()
    {
        InvokeAsync(StateHasChanged);
    }

    private string GetWarehouseName()
    {
        return WarehouseStateService.AvailableWarehouses
            .FirstOrDefault(w => w.Id == WarehouseState.CurrentWarehouseId).Name
